import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as l,e as d}from"./app-0f4fe9af.js";const a={},r=d('<p>根据 HTTP 标准，HTTP 请求可以使用多种请求方法。</p><p>HTTP1.0 定义了三种请求方法： GET, POST 和 HEAD 方法。</p><p>HTTP1.1 新增了六种请求方法：OPTIONS、PUT、PATCH、DELETE、TRACE 和 CONNECT 方法。</p><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">GET</td><td style="text-align:left;">请求指定的页面信息，并返回实体主体。</td></tr><tr><td style="text-align:left;">HEAD</td><td style="text-align:left;">类似于 GET 请求，只不过返回的响应中没有具体的内容，用于获取报头</td></tr><tr><td style="text-align:left;">POST</td><td style="text-align:left;">向指定资源提交数据进行处理请求（例如提交表单或者上传文件）。数据被包含在请求体中。POST 请求可能会导致新的资源的建立和/或已有资源的修改。</td></tr><tr><td style="text-align:left;">PUT</td><td style="text-align:left;">从客户端向服务器传送的数据取代指定的文档的内容。</td></tr><tr><td style="text-align:left;">DELETE</td><td style="text-align:left;">请求服务器删除指定的页面。</td></tr><tr><td style="text-align:left;">CONNECT</td><td style="text-align:left;">HTTP/1.1 协议中预留给能够将连接改为管道方式的代理服务器。</td></tr><tr><td style="text-align:left;">OPTIONS</td><td style="text-align:left;">允许客户端查看服务器的性能。</td></tr><tr><td style="text-align:left;">TRACE</td><td style="text-align:left;">回显服务器收到的请求，主要用于测试或诊断。</td></tr><tr><td style="text-align:left;">PATCH</td><td style="text-align:left;">是对 PUT 方法的补充，用来对已知资源进行局部更新 。</td></tr></tbody></table>',4),s=[r];function n(T,i){return e(),l("div",null,s)}const y=t(a,[["render",n],["__file","HTTP请求方法-9212b380.html.vue"]]);export{y as default};
